export interface Reactor {
  id: string;
  name: string;
  status: 'operational' | 'maintenance' | 'offline' | 'standby';
  efficiency: number; // Percentage 0-100
  powerOutput: number; // MW
  temperature: number; // Kelvin
  pressure: number; // Atmospheres
  plasmaDensity: number; // particles/m³
  confinementTime: number; // seconds
  installationDate: string;
  lastMaintenanceDate: string;
  nextMaintenanceDate: string;
  fuelConsumption: number; // kg/day
  energyProduced: number; // MWh total
  uptime: number; // percentage
  containerNumber: number; // 1-20
}

export interface EfficiencyMetrics {
  overallEfficiency: number;
  totalPowerOutput: number;
  activeReactors: number;
  totalReactors: number;
  averageUptime: number;
  totalEnergyProduced: number;
  totalFuelConsumption: number;
  efficiencyTrend: 'increasing' | 'stable' | 'decreasing';
}

export interface TimeSeriesData {
  timestamp: string;
  efficiency: number;
  powerOutput: number;
  temperature: number;
}

export interface MaintenanceSchedule {
  reactorId: string;
  reactorName: string;
  scheduledDate: string;
  type: 'routine' | 'emergency' | 'upgrade';
  estimatedDuration: number; // hours
  priority: 'low' | 'medium' | 'high' | 'critical';
}

export interface ComparisonMetrics {
  reactorId: string;
  name: string;
  efficiency: number;
  powerOutput: number;
  uptime: number;
  fuelEfficiency: number;
}

import { Reactor, TimeSeriesData, MaintenanceSchedule } from '../types';

const REACTOR_NAMES = [
  'Helios Alpha', 'Helios Beta', 'Helios Gamma', 'Helios Delta',
  'Tokamak Prime', 'Tokamak Secondary', 'Stellarator X1', 'Stellarator X2',
  'Fusion Core A', 'Fusion Core B', 'Plasma Ring 1', 'Plasma Ring 2',
  'Ignition Unit 1', 'Ignition Unit 2', 'Confinement Cell A', 'Confinement Cell B',
  'Energy Matrix 1', 'Energy Matrix 2', 'Quantum Reactor Q1', 'Quantum Reactor Q2'
];

const STATUS_OPTIONS: Array<'operational' | 'maintenance' | 'offline' | 'standby'> = [
  'operational', 'operational', 'operational', 'operational', 'operational',
  'operational', 'standby', 'maintenance'
];

function randomInRange(min: number, max: number): number {
  return Math.random() * (max - min) + min;
}

function randomInt(min: number, max: number): number {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function randomDate(start: Date, end: Date): string {
  return new Date(start.getTime() + Math.random() * (end.getTime() - start.getTime())).toISOString().split('T')[0];
}

export function generateReactor(containerNumber: number): Reactor {
  const status = STATUS_OPTIONS[Math.floor(Math.random() * STATUS_OPTIONS.length)];
  const baseEfficiency = status === 'operational' ? randomInRange(85, 98) :
                        status === 'standby' ? randomInRange(40, 60) :
                        status === 'maintenance' ? randomInRange(20, 40) : 0;

  const installationDate = randomDate(new Date(2020, 0, 1), new Date(2023, 11, 31));
  const lastMaintenance = randomDate(new Date(2023, 6, 1), new Date(2024, 0, 1));
  const nextMaintenance = randomDate(new Date(2024, 2, 1), new Date(2024, 11, 31));

  return {
    id: `reactor-${containerNumber}`,
    name: REACTOR_NAMES[containerNumber - 1],
    status,
    efficiency: parseFloat(baseEfficiency.toFixed(2)),
    powerOutput: parseFloat((baseEfficiency * 10).toFixed(2)), // Max 980 MW
    temperature: parseFloat((150000000 + randomInRange(-10000000, 10000000)).toFixed(0)), // ~150M Kelvin
    pressure: parseFloat(randomInRange(0.5, 2.5).toFixed(2)), // Atmospheres
    plasmaDensity: parseFloat((1e20 + randomInRange(-1e19, 1e19)).toFixed(2)),
    confinementTime: parseFloat(randomInRange(0.5, 3.0).toFixed(2)),
    installationDate,
    lastMaintenanceDate: lastMaintenance,
    nextMaintenanceDate: nextMaintenance,
    fuelConsumption: parseFloat(randomInRange(0.1, 0.5).toFixed(3)), // kg/day
    energyProduced: parseFloat((randomInRange(50000, 200000)).toFixed(2)), // MWh total
    uptime: parseFloat((status === 'operational' ? randomInRange(95, 99.9) :
                       status === 'standby' ? randomInRange(50, 70) :
                       status === 'maintenance' ? randomInRange(10, 30) : 0).toFixed(2)),
    containerNumber
  };
}

export function generateReactors(count: number): Reactor[] {
  const reactors: Reactor[] = [];
  for (let i = 1; i <= count; i++) {
    reactors.push(generateReactor(i));
  }
  return reactors;
}

export function generateTimeSeriesData(hours: number = 24): TimeSeriesData[] {
  const data: TimeSeriesData[] = [];
  const now = new Date();

  for (let i = hours; i >= 0; i--) {
    const timestamp = new Date(now.getTime() - i * 60 * 60 * 1000);
    data.push({
      timestamp: timestamp.toISOString(),
      efficiency: parseFloat(randomInRange(85, 98).toFixed(2)),
      powerOutput: parseFloat(randomInRange(8000, 9500).toFixed(2)),
      temperature: parseFloat((150000000 + randomInRange(-5000000, 5000000)).toFixed(0))
    });
  }

  return data;
}

export function generateMaintenanceSchedule(reactors: Reactor[]): MaintenanceSchedule[] {
  const schedules: MaintenanceSchedule[] = [];
  const types: Array<'routine' | 'emergency' | 'upgrade'> = ['routine', 'routine', 'routine', 'emergency', 'upgrade'];
  const priorities: Array<'low' | 'medium' | 'high' | 'critical'> = ['low', 'medium', 'medium', 'high', 'critical'];

  reactors.forEach(reactor => {
    if (Math.random() > 0.6) { // 40% chance of having a scheduled maintenance
      const type = types[randomInt(0, types.length - 1)];
      const priority = type === 'emergency' ? 'critical' :
                      type === 'upgrade' ? priorities[randomInt(1, 3)] :
                      priorities[randomInt(0, 2)];

      schedules.push({
        reactorId: reactor.id,
        reactorName: reactor.name,
        scheduledDate: randomDate(new Date(2024, 2, 1), new Date(2024, 8, 30)),
        type,
        estimatedDuration: type === 'routine' ? randomInt(4, 12) :
                          type === 'emergency' ? randomInt(24, 72) :
                          randomInt(48, 168),
        priority
      });
    }
  });

  return schedules.sort((a, b) => new Date(a.scheduledDate).getTime() - new Date(b.scheduledDate).getTime());
}

export function recalculateReactorData(reactor: Reactor, updates: Partial<Reactor>): Reactor {
  const updated = { ...reactor, ...updates };

  // Recalculate dependent values
  if (updates.efficiency !== undefined) {
    updated.powerOutput = parseFloat((updates.efficiency * 10).toFixed(2));
  }

  if (updates.status !== undefined) {
    if (updates.status === 'offline') {
      updated.efficiency = 0;
      updated.powerOutput = 0;
      updated.uptime = 0;
    } else if (updates.status === 'maintenance') {
      updated.efficiency = randomInRange(20, 40);
      updated.powerOutput = updated.efficiency * 10;
      updated.uptime = randomInRange(10, 30);
    }
  }

  return updated;
}

import { Reactor, EfficiencyMetrics, ComparisonMetrics } from '../types';

export function calculateEfficiencyMetrics(reactors: Reactor[]): EfficiencyMetrics {
  const activeReactors = reactors.filter(r => r.status === 'operational');
  const totalReactors = reactors.length;

  const totalPowerOutput = reactors.reduce((sum, r) => sum + r.powerOutput, 0);
  const totalEnergyProduced = reactors.reduce((sum, r) => sum + r.energyProduced, 0);
  const totalFuelConsumption = reactors.reduce((sum, r) => sum + r.fuelConsumption, 0);

  const averageEfficiency = reactors.length > 0
    ? reactors.reduce((sum, r) => sum + r.efficiency, 0) / reactors.length
    : 0;

  const averageUptime = reactors.length > 0
    ? reactors.reduce((sum, r) => sum + r.uptime, 0) / reactors.length
    : 0;

  // Simple trend calculation (could be enhanced with historical data)
  const highEfficiencyCount = reactors.filter(r => r.efficiency >= 90).length;
  const lowEfficiencyCount = reactors.filter(r => r.efficiency < 80).length;

  const efficiencyTrend: 'increasing' | 'stable' | 'decreasing' =
    highEfficiencyCount > totalReactors * 0.6 ? 'increasing' :
    lowEfficiencyCount > totalReactors * 0.3 ? 'decreasing' : 'stable';

  return {
    overallEfficiency: parseFloat(averageEfficiency.toFixed(2)),
    totalPowerOutput: parseFloat(totalPowerOutput.toFixed(2)),
    activeReactors: activeReactors.length,
    totalReactors,
    averageUptime: parseFloat(averageUptime.toFixed(2)),
    totalEnergyProduced: parseFloat(totalEnergyProduced.toFixed(2)),
    totalFuelConsumption: parseFloat(totalFuelConsumption.toFixed(3)),
    efficiencyTrend
  };
}

export function calculateComparisonMetrics(reactors: Reactor[]): ComparisonMetrics[] {
  return reactors.map(reactor => ({
    reactorId: reactor.id,
    name: reactor.name,
    efficiency: reactor.efficiency,
    powerOutput: reactor.powerOutput,
    uptime: reactor.uptime,
    fuelEfficiency: reactor.energyProduced / reactor.fuelConsumption
  })).sort((a, b) => b.efficiency - a.efficiency);
}

export function calculatePowerToWeightRatio(powerOutput: number, assumedWeight: number = 500): number {
  // Assumed weight in tons for a containerized reactor
  return parseFloat((powerOutput / assumedWeight).toFixed(2));
}

export function calculateFuelEfficiency(energyProduced: number, fuelConsumed: number): number {
  return parseFloat((energyProduced / fuelConsumed).toFixed(2));
}

export function calculateROI(
  energyProduced: number,
  energyPrice: number = 100, // $/MWh
  operatingCost: number = 50000 // $ per day
): number {
  const revenue = energyProduced * energyPrice;
  const roi = ((revenue - operatingCost) / operatingCost) * 100;
  return parseFloat(roi.toFixed(2));
}

export function predictMaintenanceDate(
  lastMaintenanceDate: string,
  uptimePercentage: number,
  efficiency: number
): string {
  const lastMaintenance = new Date(lastMaintenanceDate);

  // Base interval is 180 days, adjusted by uptime and efficiency
  const baseInterval = 180;
  const uptimeFactor = uptimePercentage / 100;
  const efficiencyFactor = efficiency / 100;

  const adjustedInterval = baseInterval * uptimeFactor * efficiencyFactor;
  const nextDate = new Date(lastMaintenance.getTime() + adjustedInterval * 24 * 60 * 60 * 1000);

  return nextDate.toISOString().split('T')[0];
}

export function getStatusColor(status: string): string {
  switch (status) {
    case 'operational':
      return 'text-fusion-green';
    case 'standby':
      return 'text-quantum-cyan';
    case 'maintenance':
      return 'text-fusion-orange';
    case 'offline':
      return 'text-fusion-red';
    default:
      return 'text-gray-500';
  }
}

export function getStatusBgColor(status: string): string {
  switch (status) {
    case 'operational':
      return 'bg-fusion-green';
    case 'standby':
      return 'bg-quantum-cyan';
    case 'maintenance':
      return 'bg-fusion-orange';
    case 'offline':
      return 'bg-fusion-red';
    default:
      return 'bg-gray-500';
  }
}

export function getEfficiencyColor(efficiency: number): string {
  if (efficiency >= 90) return 'text-fusion-green';
  if (efficiency >= 80) return 'text-quantum-cyan';
  if (efficiency >= 70) return 'text-fusion-orange';
  return 'text-fusion-red';
}

export function formatNumber(num: number, decimals: number = 2): string {
  return num.toLocaleString('en-US', {
    minimumFractionDigits: decimals,
    maximumFractionDigits: decimals
  });
}

export function formatLargeNumber(num: number): string {
  if (num >= 1e9) return `${(num / 1e9).toFixed(2)}B`;
  if (num >= 1e6) return `${(num / 1e6).toFixed(2)}M`;
  if (num >= 1e3) return `${(num / 1e3).toFixed(2)}K`;
  return num.toFixed(2);
}

