          title="Active Reactors"
          value={`${metrics.activeReactors}/${metrics.totalReactors}`}
          color="blue"
        />
        <StatCard
          title="Average Uptime"
          value={metrics.averageUptime}
          unit="%"
          color="cyan"
        />
      </div>

